struct filter_config cfg = {
.enabled = 1,
.filter_pid = 1234,
.filter_dport = 3306,
};
__u32 key = 0;
bpf_map_update_elem(config_fd, &key, &cfg, BPF_ANY);

c
// Runtime Lookup
__u32 key = 0;
struct filter_config *cfg;
cfg = bpf_map_lookup_elem(&config, &key);

// Hot-swappable Filter Logic
if (cfg->filter_pid != 0 && pid != cfg->filter_pid) {
return 0;
}
if (cfg->filter_dport != 0 && dport != cfg->filter_dport) {
return 0;
}
